import React, { useState } from 'react';
import './ClientForm.css';

function ClientForm({ onAdd }) {
  const [formData, setFormData] = useState({
    nomCli: '',
    prenomCli: '',
    adressCli: '',
    telCli: '',
    sexe: ''
  });

  const handleChange = e => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async e => {
    e.preventDefault();
    await fetch('http://localhost:3001/clients', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(formData)
    });
    onAdd();
    setFormData({ nomCli: '', prenomCli: '', adressCli: '', telCli: '', sexe: '' });
  };

  return (
    <form onSubmit={handleSubmit} className="client-form">
      <input name="nomCli" placeholder="Nom" value={formData.nomCli} onChange={handleChange} />
      <input name="prenomCli" placeholder="Prénom" value={formData.prenomCli} onChange={handleChange} />
      <input name="adressCli" placeholder="Adresse" value={formData.adressCli} onChange={handleChange} />
      <input name="telCli" placeholder="Téléphone" value={formData.telCli} onChange={handleChange} />
      <input name="sexe" placeholder="Sexe (H/F)" value={formData.sexe} onChange={handleChange} />
      <button type="submit">Ajouter</button>
    </form>
  );
}

export default ClientForm;
